module dram_cell (
    input wire [15:0] data_in,
    input wire we,
    input wire re,
    output reg [15:0] data_out
);
    reg [15:0] cell_data;

    always @(posedge we) begin
        cell_data <= data_in;
    end

    always @(posedge re) begin
        data_out <= cell_data;
    end
endmodule
